DROP TABLE IF EXISTS `student_education`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_education` (
  `student_edu_id` bigint NOT NULL AUTO_INCREMENT,
  `application_source` varchar(255) DEFAULT NULL,
  `degree` tinyint DEFAULT NULL,
  `first_counselor` varchar(255) DEFAULT NULL,
  `graduation_type` bit(1) NOT NULL,
  `has_major` bit(1) DEFAULT NULL,
  `licenses` varchar(255) DEFAULT NULL,
  `major` varchar(255) DEFAULT NULL,
  `school_name` varchar(255) DEFAULT NULL,
  `account_info_id` bigint DEFAULT NULL,
  PRIMARY KEY (`student_edu_id`),
  UNIQUE KEY `UKo5wn04kxjaj1l1brkh6i56u9o` (`account_info_id`),
  CONSTRAINT `FKq0lob8gh67py6soeis1prwu88` FOREIGN KEY (`account_info_id`) REFERENCES `student` (`student_id`),
  CONSTRAINT `student_education_chk_1` CHECK ((`degree` between 0 and 3))
) ENGINE=InnoDB AUTO_INCREMENT=550 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
