CREATE TABLE `training_non_api_log` (
  `training_non_api_log_id` bigint NOT NULL AUTO_INCREMENT,
  `atend_de` varchar(255) NOT NULL,
  `attendance_state` tinyint NOT NULL,
  `created_at` date DEFAULT NULL,
  `cstmr_nm` varchar(255) NOT NULL,
  `kor_day_nm` varchar(255) NOT NULL,
  `training_id` bigint NOT NULL,
  `trnee_cstmr_id` varchar(255) NOT NULL,
  `updated_at` date DEFAULT NULL,
  PRIMARY KEY (`training_non_api_log_id`),
  UNIQUE KEY `uq_training_student_date` (`training_id`,`trnee_cstmr_id`,`atend_de`),
  CONSTRAINT `training_non_api_log_chk_1` CHECK ((`attendance_state` between 0 and 8))
